m=recover;
i=io:std.io;
i=s:std.str;
i=j:std.json;

f=main():$i64{
    let input=io.readln();
    let data=j.parse(input);

    let toolcall=j.getfield(data;"tool_call");
    let tool=j.getstring(j.getfield(toolcall;"tool"));
    let args=j.getfield(toolcall;"arguments");
    let error=j.getfield(data;"error");
    let code=j.getstring(j.getfield(error;"code"));

    let strategy=mut."";
    let newtool=mut."";
    let newargs=mut.j.newobject();

    if(code="LIMIT_EXCEEDED"){
        strategy="retry";
        newtool=tool;
        newargs=j.newobject();
        j.setfield(newargs;"query";j.getfield(args;"query"));
        j.setfield(newargs;"limit";j.newint(100))
    }el{
        if(code="CONNECTION_REFUSED"){
            strategy="alternative";
            if(tool="database_query"){
                newtool="cache_lookup";
                newargs=j.newobject();
                j.setfield(newargs;"key";j.newstring("users"))
            }el{
                newtool=tool
            }
        }el{
            strategy="failure";
            newtool=tool
        }
    };

    let result=j.newobject();
    j.setfield(result;"strategy";j.newstring(strategy));
    let action=j.newobject();
    j.setfield(action;"tool";j.newstring(newtool));
    j.setfield(action;"arguments";newargs);
    j.setfield(result;"action";action);

    io.println(j.stringify(result));
    <0
}
